import { useEffect, useState } from "react";

export default function Sources() {
  const [articles, setArticles] = useState([]);
  const [loading, setLoading] = useState(true);

  async function fetchArticles() {
    try {
      const res = await fetch("http://localhost:5000/api/pubmed");
      if (!res.ok) throw new Error(`Failed to fetch PubMed data: ${res.status}`);
      const data = await res.json();

      // უსაფრთხო მეპინგი, თუ title არ არსებობს
      const safeArticles = data.map((article) => ({
        title: article?.title || "No title available",
        link: article?.link || "#",
        source: article?.source || "PubMed",
      }));

      setArticles(safeArticles);
    } catch (err) {
      console.error("Sources fetch error:", err);
      // თუ ერორია, დავტოვოთ ძველი სტატია ან ცარიელი
      setArticles([]);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    // თავდაპირველი fetch
    fetchArticles();

    // ყოველ 30 წამში ავტომატური განახლება
    const intervalId = setInterval(fetchArticles, 30000);

    return () => clearInterval(intervalId);
  }, []);

  return (
    <div className="page-container">
      <h1>წყაროები და კვლევები</h1>

      <p>
        ეს პლატფორმა ეფუძნება ღია, აკადემიურ და პროფესიულ წყაროებს.
        კონტენტი განკუთვნილია საგანმანათლებლო მიზნებისთვის.
      </p>

      <h2>სტატისტიკური კვლევები PubMed–ზე</h2>

      {loading ? (
        <p>Loading articles...</p>
      ) : articles.length ? (
        <ul className="sources-list">
          {articles.map((article, index) => (
            <li key={index}>
              <a href={article.link} target="_blank" rel="noreferrer">
                {article.title}
              </a>
            </li>
          ))}
        </ul>
      ) : (
        <p>No articles available at the moment.</p>
      )}
    </div>
  );
}
